/// <summary>
/// This class is data contract class for LocalInputVATReport report.
/// </summary>
[DataContractAttribute, 
SysOperationContractProcessing(classStr(ETGLocalInputVATReportUIBuilder))]
internal final class ETGLocalInputVATReportContract implements SysOperationValidatable
{
    FromDate  fromDate;
    ToDate      toDate;
    VendAccount vendAccount;

}

Method.Source:
/// <summary>
/// Gets and sets the value of the datacontract parameter FromDate
/// </summary>
/// <param name = "_fromDate">FromDate</param>
/// <returns>FromDate</returns>
[
    DataMemberAttribute('FromDate'),
    SysOperationLabelAttribute(literalStr("@ETG_New:FromDate")),
    SysOperationHelpTextAttribute(literalStr("@ETG_New:FromDate")),
    SysOperationGroupMemberAttribute('FromDate'),
    SysOperationDisplayOrderAttribute('1')
]
public FromDate parmFromDate(FromDate _fromDate = fromDate)
{
    fromDate = _fromDate;
    return fromDate;
}

/// <summary>
/// Gets and sets the value of the datacontract parameter ToDate
/// </summary>
/// <param name = "_toDate">ToDate</param>
/// <returns>ToDate</returns>
[
    DataMemberAttribute('ToDate'),
    SysOperationLabelAttribute(literalStr("@ETG_New:ToDate")),
    SysOperationHelpTextAttribute(literalStr("@ETG_New:ToDate")),
    SysOperationGroupMemberAttribute('ToDate'),
    SysOperationDisplayOrderAttribute('2')
]
public ToDate parmToDate(ToDate _toDate = toDate)
{
    toDate = _toDate;
    return toDate;
}

/// <summary>
/// Gets and sets the value of the datacontract parameter Vend Account
/// </summary>
/// <param name = "_vendAccount">VendAccount</param>
/// <returns>VendAccount</returns>
[
    DataMemberAttribute('VendAccount'),
    SysOperationLabelAttribute(literalStr("@ETG_New:VendAccount")),
    SysOperationHelpTextAttribute(literalStr("@ETG_New:VendAccount")),
    SysOperationGroupMemberAttribute('VendAccount'),
    SysOperationDisplayOrderAttribute('3')
]
public VendAccount parmVendAccount(VendAccount _vendAccount = vendAccount)
{
    vendAccount = _vendAccount;
    return vendAccount;
}

public boolean validate()
{
    boolean isValid = true;
    if (!fromDate)
    {
        isValid = checkFailed(strFmt("@ETG_New:FromDateValidation"));
    }
    if (!toDate)
    {
        isValid = checkFailed(strFmt("@ETG_New:ToDateValidation"));
    }
    if (fromDate > toDate)
    {
        isValid = checkFailed("@ETG_New:FromandToDateValidation");
    }
    return isValid;
}
